Here's how to write modern MSTest tests for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello world"),
            });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new MockHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK),
            simulateDelay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", cts.Token));
    }

    // Reusable fake handler — no mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(
            HttpResponseMessage response,
            TimeSpan simulateDelay = default)
        {
            _response = response;
            _delay = simulateDelay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request,
            CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response;
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance and design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, satisfies nullability |
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| `Assert.ThrowsExactlyAsync<T>` | Tests exact exception type (not `[ExpectedException]`) |
| Custom `HttpMessageHandler` | Testable HTTP without a mocking library |
| Pre-cancelled `CancellationTokenSource` | Verifies the token is actually forwarded to `HttpClient` |

The `[Timeout]` attribute alone won't cancel your async code — you **must** pass `TestContext.CancellationToken` into the async calls for cooperative cancellation to work.
